int toMinutes(const string& s) {
    int h = stoi(s.substr(0, 2));
    int m = stoi(s.substr(2, 2));
    return h * 60 + m;
}

void printTime(int t) {
    cout << setfill('0') << setw(2) << (t / 60) << setw(2) << (t % 60);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> diff(24 * 60 + 10, 0);
    for (int i = 0; i < n; ++i) {
        string s;
        cin >> s;
        int l = toMinutes(s.substr(0, 4));
        int r = toMinutes(s.substr(5, 4));
        l = l / 5 * 5;
        r = (r + 4) / 5 * 5;
        diff[l]++;
        diff[r]--;
    }

    int active = 0;
    int start = -1;
    for (int t = 0; t <= 24 * 60; ++t) {
        int before = active;
        active += diff[t];
        if (before == 0 && active > 0) start = t;
        if (before > 0 && active == 0) {
            printTime(start);
            cout << '-';
            printTime(t);
            cout << '\n';
        }
    }
    return 0;
}

