long long cost(int start, int len, int center) {
    long long res = 0;
    for (int i = 0; i < len; ++i) res += abs(start + i - center);
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int r, g, b;
    cin >> r >> g >> b;
    const long long INF = (1LL << 60);
    long long ans = INF;

    for (int gs = -500; gs <= 500; ++gs) {
        long long green = cost(gs, g, 0);
        long long bestRed = INF, bestBlue = INF;
        for (int rs = -1000; rs + r - 1 < gs; ++rs) {
            bestRed = min(bestRed, cost(rs, r, -100));
        }
        for (int bs = gs + g; bs <= 1000; ++bs) {
            bestBlue = min(bestBlue, cost(bs, b, 100));
        }
        ans = min(ans, bestRed + green + bestBlue);
    }
    cout << ans << '\n';
    return 0;
}

