double dist(double ax, double ay, double bx, double by) {
    double dx = ax - bx, dy = ay - by;
    return sqrt(dx * dx + dy * dy);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    double sx, sy, tx, ty, t, v;
    cin >> sx >> sy >> tx >> ty >> t >> v;
    int n;
    cin >> n;
    double limit = t * v;
    for (int i = 0; i < n; ++i) {
        double x, y;
        cin >> x >> y;
        if (dist(sx, sy, x, y) + dist(x, y, tx, ty) <= limit + 1e-9) {
            cout << "YES\n";
            return 0;
        }
    }
    cout << "NO\n";
    return 0;
}

