int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    set<int> ng;
    for (int i = 0; i < 3; ++i) {
        int x;
        cin >> x;
        ng.insert(x);
    }
    if (ng.count(n)) {
        cout << "NO\n";
        return 0;
    }

    vector<int> can(n + 1, 0);
    can[n] = 1;
    for (int step = 0; step < 100; ++step) {
        vector<int> next = can;
        for (int x = 1; x <= n; ++x) {
            if (!can[x]) continue;
            for (int d = 1; d <= 3; ++d) {
                int y = max(0, x - d);
                if (!ng.count(y)) next[y] = 1;
            }
        }
        can.swap(next);
    }
    cout << (can[0] ? "YES" : "NO") << '\n';
    return 0;
}

