const long long MOD = 1000000007LL;

long long modPow(long long a, long long e) {
    long long r = 1;
    while (e > 0) {
        if (e & 1) r = r * a % MOD;
        a = a * a % MOD;
        e >>= 1;
    }
    return r;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long n, k;
    cin >> n >> k;
    int maxN = static_cast<int>(n + k + 5);
    vector<long long> fact(maxN), invFact(maxN);
    fact[0] = 1;
    for (int i = 1; i < maxN; ++i) fact[i] = fact[i - 1] * i % MOD;
    invFact[maxN - 1] = modPow(fact[maxN - 1], MOD - 2);
    for (int i = maxN - 1; i >= 1; --i) invFact[i - 1] = invFact[i] * i % MOD;
    long long nn = n + k - 1;
    long long ans = fact[nn] * invFact[k] % MOD * invFact[nn - k] % MOD;
    cout << ans << '\n';
    return 0;
}

